'use client';

import { useState, useEffect, useRef } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { collection, query, where, orderBy, onSnapshot, addDoc, serverTimestamp, doc, getDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Message, User } from '@/types';
import { getChatId, getSharedSecret, encryptMessage, decryptMessage } from '@/lib/encryption';
import { ArrowLeft, Send } from 'lucide-react';
import { useRouter, useParams } from 'next/navigation';

export default function PersonalChatPage() {
    const { userData } = useAuth();
    const params = useParams();
    const recipientId = params.userId as string;
    const [recipient, setRecipient] = useState<User | null>(null);
    const [messages, setMessages] = useState<Message[]>([]);
    const [newMessage, setNewMessage] = useState('');
    const [loading, setLoading] = useState(true);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const router = useRouter();

    // Fetch recipient info
    useEffect(() => {
        if (!recipientId) return;

        const fetchRecipient = async () => {
            const userDoc = await getDoc(doc(db, 'users', recipientId));
            if (userDoc.exists()) {
                setRecipient({ uid: userDoc.id, ...userDoc.data() } as User);
            }
        };

        fetchRecipient();
    }, [recipientId]);

    // Fetch messages
    useEffect(() => {
        if (!userData || !recipientId) return;

        const chatId = getChatId(userData.uid, recipientId);
        const messagesQuery = query(
            collection(db, 'chats', chatId, 'messages'),
            orderBy('createdAt', 'asc')
        );

        const unsubscribe = onSnapshot(messagesQuery, (snapshot) => {
            const sharedSecret = getSharedSecret(userData.uid, recipientId);
            const fetchedMessages = snapshot.docs.map(doc => {
                const data = doc.data();
                return {
                    id: doc.id,
                    ...data,
                    text: decryptMessage(data.text, sharedSecret)
                };
            }) as Message[];

            setMessages(fetchedMessages);
            setLoading(false);
        });

        return () => unsubscribe();
    }, [userData, recipientId]);

    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    const handleSendMessage = async () => {
        if (!newMessage.trim() || !userData || !recipientId) return;

        const chatId = getChatId(userData.uid, recipientId);
        const sharedSecret = getSharedSecret(userData.uid, recipientId);
        const encryptedText = encryptMessage(newMessage.trim(), sharedSecret);

        await addDoc(collection(db, 'chats', chatId, 'messages'), {
            text: encryptedText,
            senderId: userData.uid,
            recipientId: recipientId,
            createdAt: serverTimestamp(),
            read: false
        });

        setNewMessage('');
    };

    const handleKeyPress = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleSendMessage();
        }
    };

    if (!userData) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <p className="text-gray-600">Please log in to access chat</p>
            </div>
        );
    }

    if (!recipient) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
            </div>
        );
    }

    return (
        <div className="flex flex-col h-screen bg-gray-50">
            {/* Header */}
            <div className="bg-white border-b px-4 py-3 flex items-center gap-3">
                <button
                    onClick={() => router.back()}
                    className="p-2 hover:bg-gray-100 rounded-full transition"
                >
                    <ArrowLeft className="w-5 h-5" />
                </button>
                <img
                    src={recipient.profilePic || `https://placehold.co/40x40/EFEFEFF/3B82F6?text=${recipient.name.substring(0, 1)}`}
                    alt={recipient.name}
                    className="w-10 h-10 rounded-full"
                />
                <div>
                    <h2 className="font-semibold">{recipient.name}</h2>
                    <p className="text-sm text-gray-600">Batch of {recipient.batch}</p>
                </div>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {loading ? (
                    <div className="flex items-center justify-center h-full">
                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
                    </div>
                ) : messages.length > 0 ? (
                    <>
                        {messages.map(msg => (
                            <div
                                key={msg.id}
                                className={`flex ${msg.senderId === userData.uid ? 'justify-end' : 'justify-start'}`}
                            >
                                <div
                                    className={`max-w-[70%] rounded-2xl px-4 py-2 ${msg.senderId === userData.uid
                                            ? 'bg-blue-600 text-white'
                                            : 'bg-white text-gray-900'
                                        }`}
                                >
                                    <p className="whitespace-pre-wrap break-words">{msg.text}</p>
                                </div>
                            </div>
                        ))}
                        <div ref={messagesEndRef} />
                    </>
                ) : (
                    <div className="flex items-center justify-center h-full">
                        <p className="text-gray-500">No messages yet. Start the conversation!</p>
                    </div>
                )}
            </div>

            {/* Input */}
            <div className="bg-white border-t p-4">
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={newMessage}
                        onChange={(e) => setNewMessage(e.target.value)}
                        onKeyPress={handleKeyPress}
                        placeholder="Type a message..."
                        className="flex-1 px-4 py-2 border border-gray-300 rounded-full focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    />
                    <button
                        onClick={handleSendMessage}
                        disabled={!newMessage.trim()}
                        className="p-3 bg-blue-600 text-white rounded-full hover:bg-blue-700 transition disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        <Send className="w-5 h-5" />
                    </button>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { collection, query, where, onSnapshot } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { User, Group } from '@/types';
import { MessageCircle, Users, Globe } from 'lucide-react';
import { useRouter } from 'next/navigation';

export default function MessagesPage() {
    const { userData, loading: authLoading } = useAuth();
    const [activeSection, setActiveSection] = useState<'Personal' | 'Groups' | 'Community'>('Personal');
    const [connections, setConnections] = useState<User[]>([]);
    const [groups, setGroups] = useState<Group[]>([]);
    const [loading, setLoading] = useState(true);
    const router = useRouter();

    // Fetch connections
    useEffect(() => {
        if (!userData || !userData.connections || userData.connections.length === 0) {
            setTimeout(() => {
                setConnections([]);
                setLoading(false);
            }, 0);
            return;
        }

        const usersQuery = query(collection(db, 'users'));
        const unsubscribe = onSnapshot(usersQuery, (snapshot) => {
            const allUsers = snapshot.docs.map(doc => ({
                uid: doc.id,
                ...doc.data()
            })) as User[];

            const userConnections = allUsers.filter(user =>
                userData.connections?.includes(user.uid)
            ).sort((a, b) => a.name.localeCompare(b.name));

            setConnections(userConnections);
            setLoading(false);
        });

        return () => unsubscribe();
    }, [userData]);

    // Fetch groups
    useEffect(() => {
        if (!userData || !userData.groups || userData.groups.length === 0) {
            setTimeout(() => setGroups([]), 0);
            return;
        }

        const groupsQuery = query(
            collection(db, 'groups'),
            where('members', 'array-contains', userData.uid)
        );

        const unsubscribe = onSnapshot(groupsQuery, (snapshot) => {
            const fetchedGroups = snapshot.docs.map(doc => ({
                id: doc.id,
                ...doc.data()
            })) as Group[];
            setGroups(fetchedGroups.sort((a, b) => a.groupName.localeCompare(b.groupName)));
        });

        return () => unsubscribe();
    }, [userData]);

    if (authLoading || loading) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
            </div>
        );
    }

    if (!userData) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <p className="text-gray-600">Please log in to view messages</p>
            </div>
        );
    }

    return (
        <div className="max-w-4xl mx-auto p-4">
            {/* Header */}
            <div className="flex items-center gap-3 mb-6">
                <MessageCircle className="w-8 h-8 text-blue-600" />
                <h1 className="text-2xl font-bold">Messages</h1>
            </div>

            {/* Navigation Tabs */}
            <div className="flex gap-2 mb-6 border-b">
                <button
                    onClick={() => setActiveSection('Community')}
                    className={`flex items-center gap-2 px-4 py-3 font-medium transition ${activeSection === 'Community'
                        ? 'text-blue-600 border-b-2 border-blue-600'
                        : 'text-gray-600 hover:text-gray-900'
                        }`}
                >
                    <Globe className="w-5 h-5" />
                    Community
                </button>
                <button
                    onClick={() => setActiveSection('Groups')}
                    className={`flex items-center gap-2 px-4 py-3 font-medium transition ${activeSection === 'Groups'
                        ? 'text-blue-600 border-b-2 border-blue-600'
                        : 'text-gray-600 hover:text-gray-900'
                        }`}
                >
                    <Users className="w-5 h-5" />
                    Groups
                </button>
                <button
                    onClick={() => setActiveSection('Personal')}
                    className={`flex items-center gap-2 px-4 py-3 font-medium transition ${activeSection === 'Personal'
                        ? 'text-blue-600 border-b-2 border-blue-600'
                        : 'text-gray-600 hover:text-gray-900'
                        }`}
                >
                    <MessageCircle className="w-5 h-5" />
                    Personal
                </button>
            </div>

            {/* Content */}
            <div className="space-y-2">
                {activeSection === 'Community' && (
                    <div
                        onClick={() => router.push('/messages/community')}
                        className="bg-white rounded-xl shadow-sm p-4 hover:shadow-md transition cursor-pointer"
                    >
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <div className="w-12 h-12 bg-blue-100 rounded-full flex items-center justify-center">
                                    <Globe className="w-6 h-6 text-blue-600" />
                                </div>
                                <div>
                                    <h3 className="font-semibold">Global Community Chat</h3>
                                    <p className="text-sm text-gray-600">Chat with all Loyola alumni</p>
                                </div>
                            </div>
                            <svg className="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                            </svg>
                        </div>
                    </div>
                )}

                {activeSection === 'Groups' && (
                    <>
                        {groups.length > 0 ? (
                            groups.map(group => (
                                <div
                                    key={group.id}
                                    onClick={() => router.push(`/messages/group/${group.id}`)}
                                    className="bg-white rounded-xl shadow-sm p-4 hover:shadow-md transition cursor-pointer"
                                >
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-3">
                                            <div className="w-12 h-12 bg-purple-100 rounded-full flex items-center justify-center">
                                                <Users className="w-6 h-6 text-purple-600" />
                                            </div>
                                            <div>
                                                <h3 className="font-semibold">{group.groupName}</h3>
                                                <p className="text-sm text-gray-600">{group.members.length} members</p>
                                            </div>
                                        </div>
                                        <svg className="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                                        </svg>
                                    </div>
                                </div>
                            ))
                        ) : (
                            <div className="bg-white rounded-xl shadow-sm p-8 text-center">
                                <Users className="w-16 h-16 text-gray-300 mx-auto mb-4" />
                                <p className="text-gray-500">You are not part of any groups yet</p>
                            </div>
                        )}
                    </>
                )}

                {activeSection === 'Personal' && (
                    <>
                        {connections.length > 0 ? (
                            connections.map(user => (
                                <div
                                    key={user.uid}
                                    onClick={() => router.push(`/messages/chat/${user.uid}`)}
                                    className="bg-white rounded-xl shadow-sm p-4 hover:shadow-md transition cursor-pointer"
                                >
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-3">
                                            <img
                                                src={user.profilePic || `https://placehold.co/48x48/EFEFEFF/3B82F6?text=${user.name.substring(0, 1)}`}
                                                alt={user.name}
                                                className="w-12 h-12 rounded-full"
                                            />
                                            <div>
                                                <h3 className="font-semibold">{user.name}</h3>
                                                <p className="text-sm text-gray-600">Batch of {user.batch}</p>
                                            </div>
                                        </div>
                                        <svg className="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                                        </svg>
                                    </div>
                                </div>
                            ))
                        ) : (
                            <div className="bg-white rounded-xl shadow-sm p-8 text-center">
                                <MessageCircle className="w-16 h-16 text-gray-300 mx-auto mb-4" />
                                <p className="text-gray-500">You have no connections to chat with</p>
                                <p className="text-sm text-gray-400 mt-2">Connect with alumni to start messaging</p>
                            </div>
                        )}
                    </>
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { collection, query, orderBy, onSnapshot, addDoc, updateDoc, deleteDoc, doc, serverTimestamp } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Post } from '@/types';
import { PostCard } from '@/components/feed/PostCard';
import { CreatePostModal } from '@/components/modals/CreatePostModal';
import { EditPostModal } from '@/components/modals/EditPostModal';
import { CommentModal } from '@/components/modals/CommentModal';
import { ConfirmDialog } from '@/components/modals/ConfirmDialog';
import { PenSquare } from 'lucide-react';
import Link from 'next/link';

export default function HomePage() {
  const { userData, loading: authLoading } = useAuth();
  const [posts, setPosts] = useState<Post[]>([]);
  const [loading, setLoading] = useState(true);
  const [showCreatePost, setShowCreatePost] = useState(false);
  const [editingPost, setEditingPost] = useState<Post | null>(null);
  const [commentingPost, setCommentingPost] = useState<Post | null>(null);
  const [deletingPostId, setDeletingPostId] = useState<string | null>(null);

  // Fetch posts from Firebase
  useEffect(() => {
    if (!userData) {
      setTimeout(() => setLoading(false), 0);
      return;
    }

    const postsQuery = query(
      collection(db, 'posts'),
      orderBy('createdAt', 'desc')
    );

    const unsubscribe = onSnapshot(postsQuery, (snapshot) => {
      const fetchedPosts = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as Post[];
      setPosts(fetchedPosts);
      setLoading(false);
    });

    return () => unsubscribe();
  }, [userData]);

  const handleCreatePost = async (content: string, imageUrl?: string) => {
    if (!userData) return;

    await addDoc(collection(db, 'posts'), {
      authorUid: userData.uid,
      authorName: userData.name,
      authorBatch: userData.batch,
      authorProfilePic: userData.profilePic,
      content,
      imageUrl: imageUrl || '',
      likes: [],
      comments: [],
      createdAt: serverTimestamp()
    });
  };

  const handleUpdatePost = async (postId: string, newContent: string) => {
    const postRef = doc(db, 'posts', postId);
    await updateDoc(postRef, { content: newContent });
  };

  const handleLikePost = async (postId: string, isLiked: boolean) => {
    if (!userData) return;

    const postRef = doc(db, 'posts', postId);
    const post = posts.find(p => p.id === postId);
    if (!post) return;

    const likes = post.likes || [];
    const updatedLikes = isLiked
      ? likes.filter(uid => uid !== userData.uid)
      : [...likes, userData.uid];

    await updateDoc(postRef, { likes: updatedLikes });
  };

  const handleAddComment = async (text: string) => {
    if (!userData || !commentingPost) return;

    const postRef = doc(db, 'posts', commentingPost.id);
    const post = posts.find(p => p.id === commentingPost.id);
    if (!post) return;

    const newComment = {
      authorUid: userData.uid,
      authorName: userData.name,
      text,
      createdAt: new Date()
    };

    const updatedComments = [...(post.comments || []), newComment];
    await updateDoc(postRef, { comments: updatedComments });
  };

  const handleDeletePost = async () => {
    if (!deletingPostId) return;
    await deleteDoc(doc(db, 'posts', deletingPostId));
    setDeletingPostId(null);
  };

  if (authLoading || loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading...</p>
        </div>
      </div>
    );
  }

  if (!userData) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <h2 className="text-2xl font-bold mb-4">Welcome to Alumni Network</h2>
          <p className="text-gray-600 mb-6">Please log in to continue</p>
          <div className="space-x-4">
            <Link href="/login" className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700">
              Log In
            </Link>
            <Link href="/signup" className="px-6 py-2 border border-blue-600 text-blue-600 rounded-lg hover:bg-blue-50">
              Sign Up
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto p-4">
      {/* Create Post Button */}
      <div className="bg-white rounded-xl shadow-sm p-4 mb-4">
        <button
          onClick={() => setShowCreatePost(true)}
          className="w-full flex items-center gap-3 px-4 py-3 bg-gray-100 hover:bg-gray-200 rounded-lg transition text-left"
        >
          <img
            src={userData.profilePic || `https://placehold.co/40x40/EFEFEFF/003366?text=${userData.name.substring(0, 1)}`}
            alt={userData.name}
            className="w-10 h-10 rounded-full"
          />
          <span className="text-gray-500">What&apos;s on your mind, {userData.name.split(' ')[0]}?</span>
          <PenSquare className="w-5 h-5 ml-auto text-blue-600" />
        </button>
      </div>

      {/* Posts Feed */}
      <div className="space-y-4">
        {posts.length > 0 ? (
          posts.map(post => (
            <PostCard
              key={post.id}
              post={post}
              currentUser={userData}
              onLike={(isLiked) => handleLikePost(post.id, isLiked)}
              onComment={() => setCommentingPost(post)}
              onEdit={() => setEditingPost(post)}
              onDelete={() => setDeletingPostId(post.id)}
            />
          ))
        ) : (
          <div className="bg-white rounded-xl shadow-sm p-8 text-center">
            <p className="text-gray-500">No posts yet. Be the first to share something!</p>
          </div>
        )}
      </div>

      {/* Modals */}
      <CreatePostModal
        isOpen={showCreatePost}
        onClose={() => setShowCreatePost(false)}
        onSubmit={handleCreatePost}
        currentUser={userData}
      />

      {editingPost && (
        <EditPostModal
          isOpen={true}
          onClose={() => setEditingPost(null)}
          onSubmit={handleUpdatePost}
          post={editingPost}
        />
      )}

      {commentingPost && (
        <CommentModal
          isOpen={true}
          onClose={() => setCommentingPost(null)}
          onSubmit={handleAddComment}
          comments={commentingPost.comments || []}
          postAuthor={commentingPost.authorName}
        />
      )}

      <ConfirmDialog
        isOpen={!!deletingPostId}
        onClose={() => setDeletingPostId(null)}
        onConfirm={handleDeletePost}
        title="Delete Post"
        message="Are you sure you want to delete this post? This action cannot be undone."
        confirmText="Delete"
        variant="danger"
      />
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import { uploadToImgbb } from '@/lib/imageUpload';
import { Eye, EyeOff, Loader2, Camera, ArrowLeft } from 'lucide-react';
import Link from 'next/link';

export default function SignUpPage() {
    const { signUp, error, clearError } = useAuth();
    const router = useRouter();
    const [loading, setLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: '',
        batch: new Date().getFullYear(),
        profession: '',
        location: '',
    });
    const [profilePicFile, setProfilePicFile] = useState<File | null>(null);
    const [previewUrl, setPreviewUrl] = useState<string>('');

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            // Validate file size (max 5MB)
            if (file.size > 5 * 1024 * 1024) {
                alert('Image size should be less than 5MB');
                return;
            }

            // Validate file type
            if (!file.type.startsWith('image/')) {
                alert('Please select an image file');
                return;
            }

            setProfilePicFile(file);
            setPreviewUrl(URL.createObjectURL(file));
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        clearError();

        try {
            let profilePicUrl = '';
            if (profilePicFile) {
                profilePicUrl = await uploadToImgbb(profilePicFile) || '';
            }

            await signUp(formData.email, formData.password, {
                name: formData.name,
                batch: formData.batch,
                profession: formData.profession,
                location: formData.location,
                profilePic: profilePicUrl || `https://placehold.co/100x100/EFEFEFF/003366?text=${formData.name.substring(0, 2).toUpperCase()}`,
            });

            router.push('/');
        } catch (err) {
            console.error('Sign up failed:', err);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-gradient-to-br from-blue-50 to-blue-100 flex items-center justify-center p-4">
            <div className="max-w-md w-full">
                {/* Back Button */}
                <Link href="/login" className="inline-flex items-center gap-2 text-blue-600 hover:text-blue-700 mb-6 font-medium">
                    <ArrowLeft className="w-4 h-4" />
                    Back to Login
                </Link>

                {/* Card */}
                <div className="bg-white rounded-2xl shadow-xl p-8">
                    {/* Header */}
                    <div className="text-center mb-8">
                        <div className="w-16 h-16 bg-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
                            <span className="text-2xl font-bold text-white">LA</span>
                        </div>
                        <h1 className="text-3xl font-bold text-gray-900 mb-2">Join Alumni Network</h1>
                        <p className="text-gray-600">Create your account to connect with fellow alumni</p>
                    </div>

                    {/* Error Message */}
                    {error && (
                        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg">
                            <p className="text-sm text-red-600">{error}</p>
                        </div>
                    )}

                    {/* Form */}
                    <form onSubmit={handleSubmit} className="space-y-4">
                        {/* Profile Picture */}
                        <div className="flex flex-col items-center mb-6">
                            <div className="relative group">
                                <div className="w-24 h-24 rounded-full overflow-hidden bg-gray-200 border-4 border-gray-100 shadow-md">
                                    {previewUrl ? (
                                        <img src={previewUrl} alt="Preview" className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center text-gray-400">
                                            <svg className="w-12 h-12" fill="currentColor" viewBox="0 0 20 20">
                                                <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
                                            </svg>
                                        </div>
